import{_ as e,c as n,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Inicio Rápido: Domina en 5 Minutos | Plannotator","description":"Aprende a instalar y configurar Plannotator. Completa la instalación del CLI en 5 minutos, configura el plugin de Claude Code u OpenCode, domina el flujo de revisión de planes y revisión de código.","frontmatter":{"title":"Inicio Rápido: Domina en 5 Minutos | Plannotator","sidebarTitle":"Domina en 5 minutos","subtitle":"Inicio Rápido: Domina Plannotator en 5 minutos","description":"Aprende a instalar y configurar Plannotator. Completa la instalación del CLI en 5 minutos, configura el plugin de Claude Code u OpenCode, domina el flujo de revisión de planes y revisión de código.","tags":["quick-start","getting-started","installation","claude-code","opencode"],"order":1},"headers":[],"relativePath":"es/backnotprop/plannotator/start/getting-started/index.md","filePath":"es/backnotprop/plannotator/start/getting-started/index.md"}'),s={name:"es/backnotprop/plannotator/start/getting-started/index.md"};function t(l,a,r,d,c,p){return i(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="inicio-rapido-domina-plannotator-en-5-minutos" tabindex="-1">Inicio Rápido: Domina Plannotator en 5 minutos <a class="header-anchor" href="#inicio-rapido-domina-plannotator-en-5-minutos" aria-label="Permalink to &quot;Inicio Rápido: Domina Plannotator en 5 minutos&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><ul><li>✅ Comprender las funciones principales y casos de uso de Plannotator</li><li>✅ Completar la instalación de Plannotator en 5 minutos</li><li>✅ Configurar la integración con Claude Code u OpenCode</li><li>✅ Realizar tu primera revisión de plan y revisión de código</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p><strong>Plannotator</strong> es una herramienta de revisión interactiva diseñada para Claude Code y OpenCode, que te ayuda a resolver los siguientes problemas:</p><p><strong>Problema 1</strong>: Los planes de implementación generados por IA se leen en la terminal, con gran cantidad de texto y estructura poco clara, lo que hace que la revisión sea agotadora.</p><p><strong>Problema 2</strong>: Al dar feedback a la IA, solo puedes usar descripciones de texto como &quot;eliminar el párrafo 3&quot; o &quot;modificar esta función&quot;, lo que genera un alto costo de comunicación.</p><p><strong>Problema 3</strong>: Durante la revisión de código, necesitas abrir múltiples terminales o IDEs, alternando constantemente, lo que dificulta la concentración.</p><p><strong>Problema 4</strong>: Los miembros del equipo quieren participar en la revisión, pero no saben cómo compartir el contenido del plan.</p><p><strong>Plannotator puede ayudarte</strong>:</p><ul><li>Interfaz visual en lugar de lectura en terminal, con estructura clara</li><li>Añade anotaciones (eliminar, reemplazar, comentar) seleccionando texto, feedback preciso</li><li>Revisión visual de Git diff, con soporte para anotaciones a nivel de línea</li><li>Función de compartir URL, colaboración en equipo sin necesidad de backend</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo usar esta técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo usar esta técnica&quot;">​</a></h2><p><strong>Casos de uso</strong>:</p><ul><li>Usar Claude Code u OpenCode para desarrollo asistido por IA</li><li>Necesitar revisar planes de implementación generados por IA</li><li>Necesitar revisar cambios de código</li><li>Necesitar compartir planes o resultados de revisión de código con miembros del equipo</li></ul><p><strong>Casos no adecuados</strong>:</p><ul><li>Código escrito completamente a mano (sin planes generados por IA)</li><li>Ya tienes un flujo completo de revisión de código (como GitHub PR)</li><li>No necesitas herramientas de revisión visual</li></ul><h2 id="concepto-central" tabindex="-1">Concepto central <a class="header-anchor" href="#concepto-central" aria-label="Permalink to &quot;Concepto central&quot;">​</a></h2><h3 id="que-es-plannotator" tabindex="-1">Qué es Plannotator <a class="header-anchor" href="#que-es-plannotator" aria-label="Permalink to &quot;Qué es Plannotator&quot;">​</a></h3><p><strong>Plannotator</strong> es una herramienta de revisión interactiva diseñada para AI Coding Agents (Claude Code, OpenCode), que proporciona principalmente dos funciones:</p><ol><li><strong>Revisión de planes</strong>: Revisión visual de planes de implementación generados por IA, con soporte para añadir anotaciones, aprobar o rechazar</li><li><strong>Revisión de código</strong>: Revisión visual de Git diff, con soporte para anotaciones a nivel de línea y múltiples modos de vista</li></ol><h3 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (genera plan) │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← Servidor HTTP local</span></span>
<span class="line"><span>│  (UI visual)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Navegador     │</span></span>
<span class="line"><span>│  (revisión)    │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>Flujo principal</strong>:</p><ol><li>AI Agent completa el plan o cambios de código</li><li>Plannotator inicia un servidor HTTP local y abre el navegador</li><li>El usuario revisa el plan/código en el navegador y añade anotaciones</li><li>El usuario aprueba o solicita cambios, Plannotator devuelve la decisión al AI Agent</li><li>AI Agent continúa la implementación o modifica según el feedback</li></ol><h3 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h3><p><strong>Todos los datos se procesan localmente</strong>, no se suben a la nube:</p><ul><li>El contenido del plan, código diff y anotaciones se almacenan en tu máquina local</li><li>El servidor HTTP local usa un puerto aleatorio (o puerto fijo)</li><li>La función de compartir URL se implementa comprimiendo datos en el hash de la URL, sin necesidad de backend</li></ul><h2 id="🎒-preparacion-previa" tabindex="-1">🎒 Preparación previa <a class="header-anchor" href="#🎒-preparacion-previa" aria-label="Permalink to &quot;🎒 Preparación previa&quot;">​</a></h2><p><strong>Requisitos del sistema</strong>:</p><ul><li>Sistema operativo: macOS / Linux / Windows / WSL</li><li>Runtime: Bun (el script de instalación lo maneja automáticamente)</li><li>Entorno AI: Claude Code 2.1.7+ u OpenCode</li></ul><p><strong>Selección del método de instalación</strong>:</p><ul><li>Si usas Claude Code: necesitas instalar CLI + plugin</li><li>Si usas OpenCode: necesitas configurar el plugin</li><li>Si solo haces revisión de código: solo necesitas instalar el CLI</li></ul><h2 id="paso-a-paso" tabindex="-1">Paso a paso <a class="header-anchor" href="#paso-a-paso" aria-label="Permalink to &quot;Paso a paso&quot;">​</a></h2><h3 id="paso-1-instalar-plannotator-cli" tabindex="-1">Paso 1: Instalar Plannotator CLI <a class="header-anchor" href="#paso-1-instalar-plannotator-cli" aria-label="Permalink to &quot;Paso 1: Instalar Plannotator CLI&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>Deberías ver</strong>: El script de instalación descargará automáticamente Plannotator CLI y lo añadirá a la ruta del sistema, mostrando el número de versión (como &quot;plannotator v0.6.7 installed to ...&quot;).</p><div class="tip custom-block"><p class="custom-block-title">¿Qué hace el script de instalación?</p><p>El script de instalación:</p><ol><li>Descarga la última versión de Plannotator CLI</li><li>Lo añade a la ruta del sistema (PATH)</li><li>Limpia posibles versiones antiguas</li><li>Instala automáticamente el comando <code>/plannotator-review</code> (para revisión de código)</li></ol></div><h3 id="paso-2-configurar-claude-code-opcional" tabindex="-1">Paso 2: Configurar Claude Code (opcional) <a class="header-anchor" href="#paso-2-configurar-claude-code-opcional" aria-label="Permalink to &quot;Paso 2: Configurar Claude Code (opcional)&quot;">​</a></h3><p>Si usas Claude Code, necesitas instalar el plugin.</p><p><strong>Ejecuta en Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>Importante</strong>: Después de instalar el plugin, <strong>debes reiniciar Claude Code</strong> para que los hooks se activen.</p><p><strong>Deberías ver</strong>: Después de instalar el plugin exitosamente, <code>plannotator</code> aparecerá en la lista de plugins de Claude Code.</p><div class="info custom-block"><p class="custom-block-title">Método de configuración manual (opcional)</p><p>Si no quieres usar el sistema de plugins, puedes configurar el hook manualmente. Consulta el capítulo <a href="./../installation-claude-code/">Instalación del plugin de Claude Code</a>.</p></div><h3 id="paso-3-configurar-opencode-opcional" tabindex="-1">Paso 3: Configurar OpenCode (opcional) <a class="header-anchor" href="#paso-3-configurar-opencode-opcional" aria-label="Permalink to &quot;Paso 3: Configurar OpenCode (opcional)&quot;">​</a></h3><p>Si usas OpenCode, necesitas editar el archivo <code>opencode.json</code>.</p><p><strong>Edita <code>opencode.json</code></strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Reinicia OpenCode</strong>.</p><p><strong>Deberías ver</strong>: Después de reiniciar, OpenCode cargará automáticamente el plugin y la herramienta <code>submit_plan</code> estará disponible.</p><h3 id="paso-4-primera-revision-de-plan-ejemplo-con-claude-code" tabindex="-1">Paso 4: Primera revisión de plan (ejemplo con Claude Code) <a class="header-anchor" href="#paso-4-primera-revision-de-plan-ejemplo-con-claude-code" aria-label="Permalink to &quot;Paso 4: Primera revisión de plan (ejemplo con Claude Code)&quot;">​</a></h3><p><strong>Condición de activación</strong>: Haz que Claude Code genere un plan de implementación y llame a <code>ExitPlanMode</code>.</p><p><strong>Ejemplo de diálogo</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuario: Ayúdame a escribir un plan de implementación para un módulo de autenticación de usuarios</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: De acuerdo, este es el plan de implementación:</span></span>
<span class="line"><span>1. Crear modelo de usuario</span></span>
<span class="line"><span>2. Implementar API de registro</span></span>
<span class="line"><span>3. Implementar API de inicio de sesión</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(llama a ExitPlanMode)</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ol><li>El navegador abre automáticamente la interfaz de Plannotator</li><li>Muestra el contenido del plan generado por IA</li><li>Puedes seleccionar texto del plan y añadir anotaciones (eliminar, reemplazar, comentar)</li><li>En la parte inferior hay botones &quot;Approve&quot; y &quot;Request Changes&quot;</li></ol><p><strong>Operación</strong>:</p><ol><li>Revisa el plan en el navegador</li><li>Si el plan está bien, haz clic en <strong>Approve</strong> → IA continúa la implementación</li><li>Si necesitas modificaciones, selecciona el texto a cambiar, haz clic en <strong>Delete</strong>, <strong>Replace</strong> o <strong>Comment</strong> → haz clic en <strong>Request Changes</strong></li></ol><p><strong>Deberías ver</strong>: Después de hacer clic, el navegador se cerrará automáticamente y Claude Code recibirá tu decisión y continuará ejecutando.</p><h3 id="paso-5-primera-revision-de-codigo" tabindex="-1">Paso 5: Primera revisión de código <a class="header-anchor" href="#paso-5-primera-revision-de-codigo" aria-label="Permalink to &quot;Paso 5: Primera revisión de código&quot;">​</a></h3><p><strong>Ejecuta en el directorio del proyecto</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ol><li>El navegador abre la página de revisión de código</li><li>Muestra el Git diff (por defecto son los cambios no confirmados)</li><li>A la izquierda está el árbol de archivos, a la derecha el visor de diff</li><li>Haz clic en los números de línea para seleccionar un rango de código y añadir anotaciones</li></ol><p><strong>Operación</strong>:</p><ol><li>Navega por los cambios de código en el visor de diff</li><li>Haz clic en los números de línea para seleccionar el código a revisar</li><li>Añade anotaciones en el panel derecho (comment/suggestion/concern)</li><li>Haz clic en <strong>Send Feedback</strong> para enviar al agent, o haz clic en <strong>LGTM</strong> para aprobar</li></ol><p><strong>Deberías ver</strong>: Después de hacer clic en Send Feedback, el navegador se cerrará, la terminal mostrará el feedback formateado y el agent lo procesará automáticamente.</p><h2 id="punto-de-verificacion-✅" tabindex="-1">Punto de verificación ✅ <a class="header-anchor" href="#punto-de-verificacion-✅" aria-label="Permalink to &quot;Punto de verificación ✅&quot;">​</a></h2><p>Después de completar los pasos anteriores, deberías poder:</p><ul><li>[ ] El script de instalación muestra &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] Activar la revisión de plan en Claude Code, el navegador abre automáticamente la interfaz</li><li>[ ] Seleccionar texto del plan en la interfaz y añadir anotaciones</li><li>[ ] Hacer clic en Approve o Request Changes y ver que el navegador se cierra</li><li>[ ] Ejecutar <code>/plannotator-review</code> y ver la interfaz de revisión de código</li><li>[ ] Añadir anotaciones a nivel de línea en la revisión de código y hacer clic en Send Feedback</li></ul><p><strong>Si algún paso falla</strong>, consulta:</p><ul><li><a href="./../installation-claude-code/">Guía de instalación de Claude Code</a></li><li><a href="./../installation-opencode/">Guía de instalación de OpenCode</a></li><li><a href="./../../faq/common-problems/">Preguntas frecuentes</a></li></ul><h2 id="advertencias-sobre-problemas-comunes" tabindex="-1">Advertencias sobre problemas comunes <a class="header-anchor" href="#advertencias-sobre-problemas-comunes" aria-label="Permalink to &quot;Advertencias sobre problemas comunes&quot;">​</a></h2><p><strong>Error común 1</strong>: Después de la instalación, ejecutar <code>plannotator</code> muestra &quot;command not found&quot;</p><p><strong>Causa</strong>: La variable de entorno PATH no se actualizó, o necesitas reiniciar la terminal.</p><p><strong>Solución</strong>:</p><ul><li>macOS/Linux: Ejecuta <code>source ~/.zshrc</code> o <code>source ~/.bashrc</code>, o reinicia la terminal</li><li>Windows: Reinicia PowerShell o CMD</li></ul><p><strong>Error común 2</strong>: Después de instalar el plugin en Claude Code, la revisión de plan no se activa</p><p><strong>Causa</strong>: No reiniciaste Claude Code, los hooks no se activaron.</p><p><strong>Solución</strong>: Cierra completamente Claude Code (no solo cerrar la ventana), luego vuelve a abrirlo.</p><p><strong>Error común 3</strong>: El navegador no se abre automáticamente</p><p><strong>Causa</strong>: Puede ser modo remoto (como devcontainer, SSH), o el puerto está ocupado.</p><p><strong>Solución</strong>:</p><ul><li>Verifica si configuraste la variable de entorno <code>PLANNOTATOR_REMOTE=1</code></li><li>Revisa la URL en la salida de la terminal y ábrela manualmente en el navegador</li><li>Consulta <a href="./../../advanced/remote-mode/">Modo Remoto/Devcontainer</a></li></ul><p><strong>Error común 4</strong>: La revisión de código muestra &quot;No changes&quot;</p><p><strong>Causa</strong>: Actualmente no hay cambios git sin confirmar.</p><p><strong>Solución</strong>:</p><ul><li>Primero ejecuta <code>git status</code> para confirmar que hay cambios</li><li>O ejecuta <code>git add</code> para preparar algunos archivos</li><li>O cambia a otro tipo de diff (como last commit)</li></ul><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la lección&quot;">​</a></h2><p>Plannotator es una herramienta de revisión que se ejecuta localmente, mejorando la eficiencia de la revisión de planes y código mediante una interfaz visual:</p><p><strong>Funciones principales</strong>:</p><ul><li><strong>Revisión de planes</strong>: Revisión visual de planes generados por IA, con soporte para anotaciones precisas</li><li><strong>Revisión de código</strong>: Revisión visual de Git diff, con soporte para anotaciones a nivel de línea</li><li><strong>Compartir URL</strong>: Compartir contenido de revisión sin necesidad de backend</li><li><strong>Integración con terceros</strong>: Guardar automáticamente planes aprobados en Obsidian/Bear</li></ul><p><strong>Ventajas principales</strong>:</p><ul><li>Ejecución local, datos seguros</li><li>Interfaz visual, mayor eficiencia</li><li>Feedback preciso, menor costo de comunicación</li><li>Colaboración en equipo, sin sistema de cuentas</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos sobre <strong><a href="./../installation-claude-code/">Instalación del plugin de Claude Code</a></strong>.</p><p>Aprenderás:</p><ul><li>Pasos detallados de instalación del plugin de Claude Code</li><li>Método de configuración manual de hooks</li><li>Cómo verificar que la instalación fue exitosa</li><li>Solución de problemas comunes de instalación</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver las ubicaciones del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Punto de entrada CLI (revisión de plan)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>Punto de entrada CLI (revisión de código)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>Servidor de revisión de plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>Servidor de revisión de código</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Herramientas Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>UI de revisión de plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>UI de revisión de código</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>MAX_RETRIES = 5</code>: Número de reintentos de puerto (<code>packages/server/index.ts:80</code>)</li><li><code>RETRY_DELAY_MS = 500</code>: Retraso de reintento de puerto (<code>packages/server/index.ts:80</code>)</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Inicia el servidor de revisión de plan (<code>packages/server/index.ts</code>)</li><li><code>startReviewServer()</code>: Inicia el servidor de revisión de código (<code>packages/server/review.ts</code>)</li><li><code>runGitDiff()</code>: Ejecuta el comando git diff (<code>packages/server/git.ts</code>)</li></ul><p><strong>Variables de entorno</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE</code>: Indicador de modo remoto (<code>apps/hook/server/index.ts:17</code>)</li><li><code>PLANNOTATOR_PORT</code>: Puerto fijo (<code>apps/hook/server/index.ts:18</code>)</li><li><code>PLANNOTATOR_BROWSER</code>: Navegador personalizado (<code>apps/hook/README.md:79</code>)</li><li><code>PLANNOTATOR_SHARE</code>: Interruptor de compartir URL (<code>apps/hook/server/index.ts:44</code>)</li></ul></details>`,104)])])}const h=e(s,[["render",t]]);export{g as __pageData,h as default};
